import{_ as l,O as e,H as i,f as t,b as n,j as a,k as o,i as c}from"./chunks/framework.Pt2pSV98.js";const f=JSON.parse('{"title":"翻译类模板","description":"通用翻译、商务翻译、技术文档翻译、本地化适配——四个高频翻译场景的实战 Prompt 模板","frontmatter":{"title":"翻译类模板","description":"通用翻译、商务翻译、技术文档翻译、本地化适配——四个高频翻译场景的实战 Prompt 模板","difficulty":"beginner"},"headers":[],"relativePath":"prompts/translation.md","filePath":"prompts/translation.md"}'),r={name:"prompts/translation.md"},d={id:"翻译类模板",tabindex:"-1"};function u(h,s,g,m,b,v){const p=e("DifficultyBadge");return i(),t("div",null,[n("h1",d,[s[0]||(s[0]=a("翻译类模板 ",-1)),o(p,{level:"beginner"}),s[1]||(s[1]=a()),s[2]||(s[2]=n("a",{class:"header-anchor",href:"#翻译类模板","aria-label":'Permalink to "翻译类模板 <DifficultyBadge level="beginner" />"'},"​",-1))]),s[3]||(s[3]=c(`<p>翻译是 Prompt 最实用的场景之一。相比传统翻译工具，AI 翻译的优势在于可以指定语言风格、保留术语、理解上下文，甚至进行本地化适配。以下四个模板覆盖了从日常到专业的翻译需求。</p><hr><h2 id="模板一-通用翻译" tabindex="-1">模板一：通用翻译 <a class="header-anchor" href="#模板一-通用翻译" aria-label="Permalink to &quot;模板一：通用翻译&quot;">​</a></h2><p><strong>场景说明</strong>：将一段文字翻译成指定语言，同时控制语气和风格。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请将以下中文翻译成英文，要求：</span></span>
<span class="line"><span>- 风格：自然口语化，适合日常对话</span></span>
<span class="line"><span>- 保留原文的情感和语气</span></span>
<span class="line"><span>- 如果遇到中文特有的表达（如成语、俗语），请用意译而非直译</span></span>
<span class="line"><span></span></span>
<span class="line"><span>原文：</span></span>
<span class="line"><span>「这事儿说来话长，但简单讲就是——我那天出门没看黄历。」</span></span></code></pre></div><p><strong>使用技巧</strong>：</p><ul><li>在&quot;要求&quot;中指定目标受众（如&quot;面向美国青少年&quot;），AI 会用更地道的表达</li><li>对于文学性文本，可以要求&quot;保留原文的修辞手法&quot;</li><li>不确定翻译质量时，追加一句：<code>请逐句对比原文和译文，说明你的翻译策略</code></li></ul><hr><h2 id="模板二-商务翻译" tabindex="-1">模板二：商务翻译 <a class="header-anchor" href="#模板二-商务翻译" aria-label="Permalink to &quot;模板二：商务翻译&quot;">​</a></h2><p><strong>场景说明</strong>：翻译商务邮件、合同条款、产品介绍，要求正式语气和术语一致性。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 角色</span></span>
<span class="line"><span>你是一名资深商务翻译，精通中英双语，熟悉国际贸易术语。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 任务</span></span>
<span class="line"><span>将以下中文商务邮件翻译成英文。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 要求</span></span>
<span class="line"><span>1. 语气正式专业，符合国际商务惯例</span></span>
<span class="line"><span>2. 术语保持一致：如「报价单」统一译为 &quot;quotation&quot;，「交货期」统一译为 &quot;delivery lead time&quot;</span></span>
<span class="line"><span>3. 保留原文的礼貌用语和分寸感</span></span>
<span class="line"><span>4. 如果有模糊表达，选择更正式的理解方向</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 术语表（如有）</span></span>
<span class="line"><span>- 报价单 → quotation</span></span>
<span class="line"><span>- 交货期 → delivery lead time</span></span>
<span class="line"><span>- 付款条件 → payment terms</span></span>
<span class="line"><span>- 质保期 → warranty period</span></span>
<span class="line"><span></span></span>
<span class="line"><span>原文：</span></span>
<span class="line"><span>「感谢贵司的及时回复。关于本次报价，我们希望确认以下几点：</span></span>
<span class="line"><span>1. 交货期能否从 30 天缩短至 20 天；</span></span>
<span class="line"><span>2. 付款条件是否支持 30% 预付 + 70% 货到付款；</span></span>
<span class="line"><span>3. 质保期内的售后服务包含哪些内容。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如以上条款可以满足，请发送正式报价单至我司邮箱。」</span></span></code></pre></div><p><strong>使用技巧</strong>：</p><ul><li>术语表越详细，AI 的翻译越一致——这对长文档翻译尤其重要</li><li>可以上传公司已有的翻译记忆库（TM）作为参考</li><li>翻译合同条款时，建议追加：<code>请用括号标注可能有歧义的表达，并给出备选翻译</code></li></ul><hr><h2 id="模板三-技术文档翻译" tabindex="-1">模板三：技术文档翻译 <a class="header-anchor" href="#模板三-技术文档翻译" aria-label="Permalink to &quot;模板三：技术文档翻译&quot;">​</a></h2><p><strong>场景说明</strong>：翻译技术文档、API 说明、README 等，核心要求是代码和术语不译。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 任务</span></span>
<span class="line"><span>将以下技术文档从英文翻译成中文。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 关键规则</span></span>
<span class="line"><span>1. **代码不译**：所有代码块、变量名、函数名、命令行保持原样</span></span>
<span class="line"><span>2. **术语统一**：</span></span>
<span class="line"><span>   - middleware → 中间件</span></span>
<span class="line"><span>   - hook → 钩子</span></span>
<span class="line"><span>   - state → 状态</span></span>
<span class="line"><span>   - dependency → 依赖</span></span>
<span class="line"><span>   - 首次出现的术语，在中文后加括号标注英文原文</span></span>
<span class="line"><span>3. 技术描述的准确性优先于语言流畅性</span></span>
<span class="line"><span>4. 保留原文的 Markdown 格式和代码块结构</span></span>
<span class="line"><span></span></span>
<span class="line"><span>原文：</span></span>
<span class="line"><span>&lt;待翻译的技术文档&gt;</span></span></code></pre></div><p><strong>使用技巧</strong>：</p><ul><li>把这份 Prompt 保存为固定模板，每次粘贴待翻译内容即可</li><li>如果文档包含 API 参数说明，可以追加规则：&quot;参数名不译，参数说明翻译&quot;</li><li>对于大型文档，分段落翻译比一次性翻译质量更高</li></ul><hr><h2 id="模板四-本地化适配" tabindex="-1">模板四：本地化适配 <a class="header-anchor" href="#模板四-本地化适配" aria-label="Permalink to &quot;模板四：本地化适配&quot;">​</a></h2><p><strong>场景说明</strong>：不仅仅是翻译，还要考虑目标市场的文化差异、习惯表达和本地规范。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 角色</span></span>
<span class="line"><span>你是一名资深本地化专家，擅长将产品内容适配到中国大陆市场。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 任务</span></span>
<span class="line"><span>将以下英文 App 介绍页面进行本地化处理（不是字面翻译）。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 本地化要求</span></span>
<span class="line"><span>1. 将英制单位转换为公制（如 mile → 公里，pound → 公斤）</span></span>
<span class="line"><span>2. 将西方节日、文化引用替换为中国用户熟悉的对应内容</span></span>
<span class="line"><span>3. 调整语气：英文幽默可能不适合中文市场，请用更真诚、务实的语气</span></span>
<span class="line"><span>4. 保留产品的核心卖点，但用中国用户关心的表达方式重述</span></span>
<span class="line"><span>5. 格式上：英文标题（供参考）→ 中文标题 → 中文正文</span></span>
<span class="line"><span></span></span>
<span class="line"><span>原文：</span></span>
<span class="line"><span>&lt;待本地化的内容&gt;</span></span></code></pre></div><p><strong>使用技巧</strong>：</p><ul><li>本地化不是翻译，是「再创作」——给 AI 充分的修改自由度</li><li>可以要求 AI 先给出&quot;本地化策略说明&quot;，确认方向后再生成内容</li><li>对于敏感内容（政治、宗教、文化符号），建议追加要求：<code>如果遇到可能在中国市场引发争议的内容，请标注并给出修改建议</code></li></ul><hr><h2 id="翻译类-prompt-通用原则" tabindex="-1">翻译类 Prompt 通用原则 <a class="header-anchor" href="#翻译类-prompt-通用原则" aria-label="Permalink to &quot;翻译类 Prompt 通用原则&quot;">​</a></h2><ol><li><strong>告诉 AI 受众是谁</strong>——给小学生看的翻译和给 CEO 看的翻译完全不同</li><li><strong>提供术语表</strong>——这是翻译质量一致性的关键</li><li><strong>明确不可译内容</strong>——代码、品牌名、专有名词</li><li><strong>分轮次校对</strong>——第一轮翻译 → 第二轮润色 → 第三轮术语检查</li><li><strong>善用回译验证</strong>——让 AI 把译文再翻回原文，对比差异</li></ol>`,28))])}const k=l(r,[["render",u]]);export{f as __pageData,k as default};
